# Python 3.11+
"""Eviction policies — the pluggable seam that answers ONE question:
"when the cache is over capacity, which entry gets thrown out?"

🎙️ "I keep WHICH-to-evict separate from the cache. The default is LRU, which is
basically free: the linked list already orders entries by recency, so the victim
is just the tail. LFU is the harder cousin — it can't ride the recency order, so
it keeps its own frequency counts. Swapping the rule is a new class; the cache
never changes — that's the Strategy pattern."
"""

from abc import ABC, abstractmethod

from models import DoublyLinkedList, Node


class EvictionPolicy(ABC):
    # ── WHY THIS CLASS ──────────────────────────────────────────────────────
    # The abstraction the cache depends on (Dependency Inversion). The cache tells
    # the policy about every access / insert / removal; when full, it asks the
    # policy for the victim. LRU ignores the hooks (recency already lives in the
    # list); LFU uses them to maintain counts. That asymmetry IS the point of the seam.
    @abstractmethod
    def record_access(self, node: Node) -> None:
        """Called on every get, and on an update of an already-present key."""
        raise NotImplementedError

    @abstractmethod
    def record_insert(self, node: Node) -> None:
        """Called when a brand-new key is inserted."""
        raise NotImplementedError

    @abstractmethod
    def record_removal(self, node: Node) -> None:
        """Called when a node leaves the cache (eviction OR explicit remove)."""
        raise NotImplementedError

    @abstractmethod
    def select_victim(self, order: DoublyLinkedList) -> Node:
        """Return the node to evict. MUST NOT mutate the list — the caller unlinks it."""
        raise NotImplementedError


class LRUEviction(EvictionPolicy):
    """Least-Recently-Used: the victim is whoever sits at the TAIL of the recency list.

    The recency order is maintained by the cache's `move_to_front` on every access,
    so this policy keeps NO state of its own — victim selection is a single O(1) peek.
    """

    def record_access(self, node: Node) -> None:
        # No-op: the cache's doubly-linked list already records recency for us.
        return

    def record_insert(self, node: Node) -> None:
        return

    def record_removal(self, node: Node) -> None:
        return

    def select_victim(self, order: DoublyLinkedList) -> Node:
        # WHY: the tail is the least-recently-used node by construction, so picking
        #      the LRU victim is a single O(1) pointer read — no scan, no bookkeeping.
        return order.back()


class LFUEviction(EvictionPolicy):
    """Least-Frequently-Used: the victim is whoever has been accessed the fewest times.

    Unlike LRU this cannot piggyback on the recency list, so it keeps its OWN
    frequency map. Ties (same frequency) are broken by recency — among the coldest
    entries we drop the least-recently-used, which is why we still walk the list.
    """

    def __init__(self) -> None:
        self._freq: dict[Node, int] = {}  # node -> how many times it has been used

    def record_access(self, node: Node) -> None:
        self._freq[node] = self._freq.get(node, 0) + 1

    def record_insert(self, node: Node) -> None:
        self._freq[node] = 1  # an insert counts as the entry's first use

    def record_removal(self, node: Node) -> None:
        # WHY: safe to call twice — a missing node just no-ops, so eviction and an
        #      explicit remove of the same node can't blow up.
        self._freq.pop(node, None)

    def select_victim(self, order: DoublyLinkedList) -> Node:
        # WHY: find the lowest frequency, then among equally-cold nodes take the
        #      least-recently-used (closest to the tail). This is O(n); §5.5-C
        #      describes the O(1) frequency-bucket upgrade I'd make past ~10K entries.
        if not self._freq:
            return order.back()
        min_freq = min(self._freq.values())
        for node in order.iter_back_to_front():
            if self._freq.get(node, 0) == min_freq:
                return node
        return order.back()  # fallback; unreachable while the freq map stays in sync

